import{_ as a,c as n,o as e,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Команды: мониторинг и очистка | opencode-dynamic-context-pruning","description":"Изучите 4 команды DCP для мониторинга и ручной очистки. Узнайте, как использовать /dcp context для просмотра сессии, /dcp stats для статистики и /dcp sweep для ручной очистки.","frontmatter":{"title":"Команды: мониторинг и очистка | opencode-dynamic-context-pruning","sidebarTitle":"Мониторинг токенов, ручная очистка","subtitle":"Руководство по командам DCP: мониторинг и ручная очистка","description":"Изучите 4 команды DCP для мониторинга и ручной очистки. Узнайте, как использовать /dcp context для просмотра сессии, /dcp stats для статистики и /dcp sweep для ручной очистки.","tags":["Команды DCP","Мониторинг токенов","Ручная очистка"],"prerequisite":["start-getting-started","platforms-auto-pruning"],"order":3},"headers":[],"relativePath":"ru/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md","filePath":"ru/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"}'),o={name:"ru/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"};function p(d,s,l,c,i,r){return e(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="руководство-по-командам-dcp-мониторинг-и-ручная-очистка" tabindex="-1">Руководство по командам DCP: мониторинг и ручная очистка <a class="header-anchor" href="#руководство-по-командам-dcp-мониторинг-и-ручная-очистка" aria-label="Permalink to &quot;Руководство по командам DCP: мониторинг и ручная очистка&quot;">​</a></h1><h2 id="что-вы-научитесь-делать" tabindex="-1">Что вы научитесь делать <a class="header-anchor" href="#что-вы-научитесь-делать" aria-label="Permalink to &quot;Что вы научитесь делать&quot;">​</a></h2><ul><li>Использовать <code>/dcp context</code> для просмотра распределения токенов текущей сессии</li><li>Использовать <code>/dcp stats</code> для просмотра накопленной статистики очистки</li><li>Использовать <code>/dcp sweep [n]</code> для ручного запуска очистки</li><li>Понимать механизм защиты инструментов и файлов</li><li>Разбираться в стратегии подсчёта токенов и эффекте экономии</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>В длинных диалогах токены расходуются всё быстрее, но вы не знаете:</p><ul><li>На что тратятся токены текущей сессии?</li><li>Сколько именно сэкономил DCP?</li><li>Как вручную очистить ненужные выводы инструментов?</li><li>Какие инструменты защищены от очистки?</li></ul><p>Без понимания этих вопросов вы не сможете полностью использовать оптимизацию DCP и можете случайно удалить важную информацию в критический момент.</p><h2 id="когда-использовать-этот-подход" tabindex="-1">Когда использовать этот подход <a class="header-anchor" href="#когда-использовать-этот-подход" aria-label="Permalink to &quot;Когда использовать этот подход&quot;">​</a></h2><p>Когда вы:</p><ul><li>Хотите понять структуру токенов текущей сессии</li><li>Нужно быстро очистить историю диалога</li><li>Хотите проверить эффект очистки DCP</li><li>Готовитесь к новой задаче и хотите очистить контекст</li></ul><h2 id="основная-концепция" tabindex="-1">Основная концепция <a class="header-anchor" href="#основная-концепция" aria-label="Permalink to &quot;Основная концепция&quot;">​</a></h2><p>DCP предоставляет 4 Slash-команды для мониторинга и управления использованием токенов:</p><table tabindex="0"><thead><tr><th>Команда</th><th>Назначение</th><th>Сценарий использования</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>Показать справку</td><td>Когда забыли команды</td></tr><tr><td><code>/dcp context</code></td><td>Анализ распределения токенов сессии</td><td>Понимание структуры контекста</td></tr><tr><td><code>/dcp stats</code></td><td>Просмотр накопленной статистики</td><td>Проверка долгосрочного эффекта</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>Ручная очистка инструментов</td><td>Быстрое уменьшение размера контекста</td></tr></tbody></table><p><strong>Механизм защиты</strong>:</p><p>Все операции очистки автоматически пропускают:</p><ul><li><strong>Защищённые инструменты</strong>: <code>task</code>, <code>todowrite</code>, <code>todoread</code>, <code>discard</code>, <code>extract</code>, <code>batch</code>, <code>write</code>, <code>edit</code>, <code>plan_enter</code>, <code>plan_exit</code></li><li><strong>Защищённые файлы</strong>: пути файлов, соответствующие <code>protectedFilePatterns</code> в конфигурации</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Настройки защищённых инструментов и файлов можно изменить через файл конфигурации. Подробнее см. <a href="./../../start/configuration/">Полное руководство по конфигурации</a>.</p></div><h2 id="пошаговое-руководство" tabindex="-1">Пошаговое руководство <a class="header-anchor" href="#пошаговое-руководство" aria-label="Permalink to &quot;Пошаговое руководство&quot;">​</a></h2><h3 id="шаг-1-просмотр-справки" tabindex="-1">Шаг 1: Просмотр справки <a class="header-anchor" href="#шаг-1-просмотр-справки" aria-label="Permalink to &quot;Шаг 1: Просмотр справки&quot;">​</a></h3><p>Введите <code>/dcp</code> в диалоговом окне OpenCode.</p><p><strong>Вы должны увидеть</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><p><strong>Контрольная точка ✅</strong>: Убедитесь, что видите описание 3 подкоманд.</p><h3 id="шаг-2-анализ-распределения-токенов-сессии" tabindex="-1">Шаг 2: Анализ распределения токенов сессии <a class="header-anchor" href="#шаг-2-анализ-распределения-токенов-сессии" aria-label="Permalink to &quot;Шаг 2: Анализ распределения токенов сессии&quot;">​</a></h3><p>Введите <code>/dcp context</code> для просмотра использования токенов текущей сессии.</p><p><strong>Вы должны увидеть</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                  DCP Context Analysis                     │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><p><strong>Описание категорий токенов</strong>:</p><table tabindex="0"><thead><tr><th>Категория</th><th>Способ расчёта</th><th>Описание</th></tr></thead><tbody><tr><td><strong>System</strong></td><td><code>firstAssistant.input + cache.read - tokenizer(firstUserMessage)</code></td><td>Системный промпт</td></tr><tr><td><strong>Tools</strong></td><td><code>tokenizer(toolInputs + toolOutputs) - prunedTokens</code></td><td>Вызовы инструментов (за вычетом очищенных)</td></tr><tr><td><strong>User</strong></td><td><code>tokenizer(all user messages)</code></td><td>Все сообщения пользователя</td></tr><tr><td><strong>Assistant</strong></td><td><code>total - system - user - tools</code></td><td>Текстовый вывод ИИ + токены рассуждений</td></tr></tbody></table><p><strong>Контрольная точка ✅</strong>: Убедитесь, что видите процентное соотношение и количество токенов по категориям.</p><h3 id="шаг-3-просмотр-накопленнои-статистики-очистки" tabindex="-1">Шаг 3: Просмотр накопленной статистики очистки <a class="header-anchor" href="#шаг-3-просмотр-накопленнои-статистики-очистки" aria-label="Permalink to &quot;Шаг 3: Просмотр накопленной статистики очистки&quot;">​</a></h3><p>Введите <code>/dcp stats</code> для просмотра исторической статистики очистки.</p><p><strong>Вы должны увидеть</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                    DCP Statistics                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens pruned: ~15.2K</span></span>
<span class="line"><span>  Tools pruned:   12</span></span>
<span class="line"><span></span></span>
<span class="line"><span>All-time:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens saved:  ~284.5K</span></span>
<span class="line"><span>  Tools pruned:   156</span></span>
<span class="line"><span>  Sessions:       8</span></span></code></pre></div><p><strong>Описание статистики</strong>:</p><ul><li><strong>Session</strong>: данные очистки текущей сессии (в памяти)</li><li><strong>All-time</strong>: накопленные данные всех сессий (сохранены на диске)</li></ul><p><strong>Контрольная точка ✅</strong>: Убедитесь, что видите статистику текущей сессии и историческую статистику.</p><h3 id="шаг-4-ручная-очистка-инструментов" tabindex="-1">Шаг 4: Ручная очистка инструментов <a class="header-anchor" href="#шаг-4-ручная-очистка-инструментов" aria-label="Permalink to &quot;Шаг 4: Ручная очистка инструментов&quot;">​</a></h3><p>Есть два способа использования <code>/dcp sweep</code>:</p><h4 id="способ-1-очистка-всех-инструментов-после-последнего-сообщения-пользователя" tabindex="-1">Способ 1: Очистка всех инструментов после последнего сообщения пользователя <a class="header-anchor" href="#способ-1-очистка-всех-инструментов-после-последнего-сообщения-пользователя" aria-label="Permalink to &quot;Способ 1: Очистка всех инструментов после последнего сообщения пользователя&quot;">​</a></h4><p>Введите <code>/dcp sweep</code> (без параметров).</p><p><strong>Вы должны увидеть</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept 8 tool(s) since previous user message.</span></span>
<span class="line"><span>Tokens saved: ~12,345</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/config.ts</span></span>
<span class="line"><span>  • Read: src/utils.ts</span></span>
<span class="line"><span>  • Bash: npm test</span></span>
<span class="line"><span>  • Read: package.json</span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span></code></pre></div><h4 id="способ-2-очистка-последних-n-инструментов" tabindex="-1">Способ 2: Очистка последних N инструментов <a class="header-anchor" href="#способ-2-очистка-последних-n-инструментов" aria-label="Permalink to &quot;Способ 2: Очистка последних N инструментов&quot;">​</a></h4><p>Введите <code>/dcp sweep 5</code> для очистки последних 5 инструментов.</p><p><strong>Вы должны увидеть</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept last 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span>
<span class="line"><span>  • Bash: npm run build</span></span></code></pre></div><p><strong>Уведомление о защищённых инструментах</strong>:</p><p>Если были пропущены защищённые инструменты, вывод покажет:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swept 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span>(2 protected tool(s) skipped)</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Защищённые инструменты (такие как <code>write</code>, <code>edit</code>) и защищённые пути файлов автоматически пропускаются и не очищаются.</p></div><p><strong>Контрольная точка ✅</strong>: Убедитесь, что видите список очищенных инструментов и количество сэкономленных токенов.</p><h3 id="шаг-5-повторная-проверка-эффекта-очистки" tabindex="-1">Шаг 5: Повторная проверка эффекта очистки <a class="header-anchor" href="#шаг-5-повторная-проверка-эффекта-очистки" aria-label="Permalink to &quot;Шаг 5: Повторная проверка эффекта очистки&quot;">​</a></h3><p>После очистки снова введите <code>/dcp context</code> для просмотра нового распределения токенов.</p><p><strong>Вы должны увидеть</strong>:</p><ul><li>Уменьшение доли категории <code>Tools</code></li><li>Увеличение количества очищенных инструментов в <code>Summary</code></li><li>Уменьшение общего <code>Current context</code></li></ul><p><strong>Контрольная точка ✅</strong>: Убедитесь, что использование токенов заметно снизилось.</p><h2 id="типичные-ошибки" tabindex="-1">Типичные ошибки <a class="header-anchor" href="#типичные-ошибки" aria-label="Permalink to &quot;Типичные ошибки&quot;">​</a></h2><h3 id="❌-ошибка-случаиное-удаление-важных-инструментов" tabindex="-1">❌ Ошибка: случайное удаление важных инструментов <a class="header-anchor" href="#❌-ошибка-случаиное-удаление-важных-инструментов" aria-label="Permalink to &quot;❌ Ошибка: случайное удаление важных инструментов&quot;">​</a></h3><p><strong>Сценарий</strong>: Вы только что использовали инструмент <code>write</code> для создания важного файла, а затем выполнили <code>/dcp sweep</code>.</p><p><strong>Неправильный результат</strong>: Инструмент <code>write</code> очищен, ИИ может не знать, что файл был создан.</p><p><strong>Правильный подход</strong>:</p><ul><li>Инструменты <code>write</code>, <code>edit</code> и другие защищены по умолчанию</li><li>Не изменяйте вручную конфигурацию <code>protectedTools</code> для удаления этих инструментов</li><li>После завершения критических задач подождите несколько ходов перед очисткой</li></ul><h3 id="❌-ошибка-неподходящее-время-для-очистки" tabindex="-1">❌ Ошибка: неподходящее время для очистки <a class="header-anchor" href="#❌-ошибка-неподходящее-время-для-очистки" aria-label="Permalink to &quot;❌ Ошибка: неподходящее время для очистки&quot;">​</a></h3><p><strong>Сценарий</strong>: Диалог только начался, всего несколько вызовов инструментов, а вы уже выполняете <code>/dcp sweep</code>.</p><p><strong>Неправильный результат</strong>: Экономия токенов минимальна, при этом может нарушиться связность контекста.</p><p><strong>Правильный подход</strong>:</p><ul><li>Дождитесь определённого прогресса диалога (например, 10+ вызовов инструментов) перед очисткой</li><li>Очищайте выводы инструментов предыдущего раунда перед началом новой задачи</li><li>Используйте <code>/dcp context</code> для оценки целесообразности очистки</li></ul><h3 id="❌-ошибка-чрезмерная-зависимость-от-ручнои-очистки" tabindex="-1">❌ Ошибка: чрезмерная зависимость от ручной очистки <a class="header-anchor" href="#❌-ошибка-чрезмерная-зависимость-от-ручнои-очистки" aria-label="Permalink to &quot;❌ Ошибка: чрезмерная зависимость от ручной очистки&quot;">​</a></h3><p><strong>Сценарий</strong>: Вы вручную выполняете <code>/dcp sweep</code> в каждом диалоге.</p><p><strong>Неправильный результат</strong>:</p><ul><li>Стратегии автоматической очистки (дедупликация, перезапись, удаление ошибок) не используются</li><li>Увеличивается операционная нагрузка</li></ul><p><strong>Правильный подход</strong>:</p><ul><li>Включите стратегии автоматической очистки по умолчанию (конфигурация: <code>strategies.*.enabled</code>)</li><li>Используйте ручную очистку как дополнение, когда это необходимо</li><li>Проверяйте эффект автоматической очистки через <code>/dcp stats</code></li></ul><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><p>4 команды DCP помогают мониторить и контролировать использование токенов:</p><table tabindex="0"><thead><tr><th>Команда</th><th>Основная функция</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>Показать справочную информацию</td></tr><tr><td><code>/dcp context</code></td><td>Анализ распределения токенов сессии</td></tr><tr><td><code>/dcp stats</code></td><td>Просмотр накопленной статистики очистки</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>Ручная очистка инструментов</td></tr></tbody></table><p><strong>Стратегия подсчёта токенов</strong>:</p><ul><li>System: системный промпт (вычисляется из первого ответа)</li><li>Tools: ввод и вывод инструментов (за вычетом очищенных)</li><li>User: все сообщения пользователя (оценка)</li><li>Assistant: вывод ИИ + токены рассуждений (остаток)</li></ul><p><strong>Механизм защиты</strong>:</p><ul><li>Защищённые инструменты: <code>task</code>, <code>todowrite</code>, <code>todoread</code>, <code>discard</code>, <code>extract</code>, <code>batch</code>, <code>write</code>, <code>edit</code>, <code>plan_enter</code>, <code>plan_exit</code></li><li>Защищённые файлы: glob-паттерны из конфигурации</li><li>Все операции очистки автоматически пропускают эти элементы</li></ul><p><strong>Лучшие практики</strong>:</p><ul><li>Регулярно проверяйте <code>/dcp context</code> для понимания структуры токенов</li><li>Выполняйте <code>/dcp sweep</code> перед новой задачей для очистки истории</li><li>Полагайтесь на автоматическую очистку, ручную используйте как дополнение</li><li>Проверяйте долгосрочный эффект через <code>/dcp stats</code></li></ul><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../../advanced/protection/">Механизм защиты</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как защита раундов предотвращает ошибочную очистку</li><li>Как настроить список защищённых инструментов</li><li>Как настроить паттерны защищённых файлов</li><li>Особенности обработки сессий субагентов</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть расположение исходного кода</strong></summary><blockquote><p>Дата обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Команда /dcp help</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>19-32</td></tr><tr><td>Команда /dcp context</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>238-247</td></tr><tr><td>Стратегия подсчёта токенов</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>5-38</td></tr><tr><td>Команда /dcp stats</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/stats.ts" target="_blank" rel="noreferrer"><code>lib/commands/stats.ts</code></a></td><td>46-67</td></tr><tr><td>Команда /dcp sweep</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/sweep.ts" target="_blank" rel="noreferrer"><code>lib/commands/sweep.ts</code></a></td><td>123-259</td></tr><tr><td>Конфигурация защищённых инструментов</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>461</td></tr><tr><td>Список защищённых инструментов по умолчанию</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>150-151</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>DEFAULT_PROTECTED_TOOLS</code>: список защищённых инструментов по умолчанию</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>handleHelpCommand()</code>: обработка команды /dcp help</li><li><code>handleContextCommand()</code>: обработка команды /dcp context</li><li><code>analyzeTokens()</code>: подсчёт токенов по категориям</li><li><code>handleStatsCommand()</code>: обработка команды /dcp stats</li><li><code>handleSweepCommand()</code>: обработка команды /dcp sweep</li><li><code>buildToolIdList()</code>: построение списка ID инструментов</li></ul></details>`,88)])])}const g=a(o,[["render",p]]);export{u as __pageData,g as default};
